import GoogleMapReact from 'google-map-react';
import { LoadScript } from '@react-google-maps/api';
import cls from './MapPin.module.scss';
import { useState, useRef, useEffect, useCallback } from 'react';

import { setKey, setDefaults, setLanguage, setRegion, fromAddress, fromLatLng, fromPlaceId, setLocationType, geocode, RequestType } from 'react-geocode';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faLocationArrow, faLocationCrosshairs, faLocationPin, faMapPin, faSearch, faSearchPlus } from '@fortawesome/free-solid-svg-icons';
import SelectWithSearch from '../UI/Select/SelectWithSearch';
import Button from '../UI/Button/Button';

const R = require('ramda');

const MapPin = props => {
	const { onLocationChange = () => { }, value, mapkey = '', onChange = () => { } } = props;
	const latRef = useRef(150.9171779);
	const lngRef = useRef(-33.8149597);
	const [address, setAddress] = useState(value?.address ?? '');
	const [addressArray, setAddressArray] = useState([]);
	const [currentLocation, setCurrentLocation] = useState({});
	const [points, setPoints] = useState({ id: 1, title: value?.lat ? 'Target Location' : 'Current Location', lat: value?.lat ?? 0, lng: value?.lng ?? 0 });

	useEffect(() => {
		setKey(mapkey);
		navigator.geolocation.getCurrentPosition(
			location => {
				if (!(value?.lat && value?.lng)) {
					if (location) {
						setPoints({ id: 1, title: 'Current Location', lat: location.coords.latitude, lng: location.coords.longitude });
						setCurrentLocation({ id: 1, title: 'Current Location', lat: location.coords.latitude, lng: location.coords.longitude });
					}
				}
			},
			error => console.log(error)
		);

	}, []);


	const MyMarker = ({ text, tooltip }) => (
		<div className={cls.xcircle}>
			<span className={cls.circleText} title={tooltip}>
				<FontAwesomeIcon icon={faMapPin} style={{ color: 'white', width: '50px', height: '50px' }} />
				{text}
			</span>
		</div>
	);
	const distanceToMouse = (pt, mp) => {
		if (pt && mp) {
			return Math.sqrt((pt.x - mp.x) * (pt.x - mp.x) + (pt.y - mp.y) * (pt.y - mp.y));
		}
	};
	return (
		<div style={{ height: '600px', width: '100%', margin: '20px' }}>
			<div style={{ display: 'flex', width: '92%', margin: '0 10px 0 10px' }}>


				<SelectWithSearch
					id={'address'}
					isAlwaysOpen={true}
					itemType={'no-item-icons'}
					className={cls.multiselectComponent}
					inputClassName={cls.selectText}
					molclassname={cls.industryMOL}
					moliclassname={cls.industryMOLI}
					onChange={val => {
						onChange(val.value);
					}}
					items={addressArray}
				>
					<Button
						clear
						clicked={() => {

							if (Object.keys(currentLocation).length > 0) {

								setPoints(currentLocation);

								fromLatLng(currentLocation.lat, currentLocation.lng)
									.then(({ results }) => {
										setAddress(results[0].formatted_address);
										setAddressArray(
											results.map(res => {
												return {
													label: res.formatted_address,
													value: res,
												};
											})
										);
									})
									.catch(console.error);
							}
						}}
						icon={
							<FontAwesomeIcon
								icon={faLocationCrosshairs}
								style={{ width: '20px', height: '20px' }}

							/>
						}
					/>
					<input
						onBlur={e => {
							if (e.target.value.length > 3) {
								geocode(RequestType.ADDRESS, address)
									.then(({ results }) => {
										const { lat, lng } = results[0].geometry.location;

										setPoints({
											id: 1,
											title: 'Target Location',
											lat: lat,
											lng: lng,
										});

										setAddressArray(
											results.map(res => {
												return {
													label: res.formatted_address,
													value: res,
												};
											})
										);
									})
									.catch(console.error);
							} else {
								setAddressArray([]);
							}
						}}
						type={'text'}
						onChange={e => {
							setAddress(e.target.value);
						}}
						value={address}
						autoComplete="none"
						className={cls.fieldTypeInput}
						placeholder="Type address"
					/>
					<Button
						clear
						icon={
							<FontAwesomeIcon
								icon={faSearch}
								style={{ width: '20px', height: '20px' }}
								clicked={() => {
									if (address.length > 3) {
										geocode(RequestType.ADDRESS, address)
											.then(({ results }) => {
												const { lat, lng } = results[0].geometry.location;

												setPoints({
													id: 1,
													title: 'Target Location',
													lat: lat,
													lng: lng,
												});

												setAddressArray(
													results.map(res => {
														return {
															label: res.formatted_address,
															value: res,
														};
													})
												);
											})
											.catch(console.error);
									}
								}}
							/>
						}
					/>
				</SelectWithSearch>


			</div>

			<div style={{ marginTop: '20px', height: '80%', width: '100%' }}>
				<GoogleMapReact
					onClick={ev => {
						fromLatLng(ev.lat, ev.lng)
							.then(({ results }) => {
								setAddress(results[0].formatted_address);
								setAddressArray(
									results.map(res => {
										return {
											label: res.formatted_address,
											value: res,
										};
									})
								);
							})
							.catch(console.error);

						setPoints({
							id: 1,
							title: 'Target Location',
							lat: ev.lat,
							lng: ev.lng,
						});
					}}
					bootstrapURLKeys={{
						key: '',
						language: 'en',
						region: 'US',
					}}
					center={{ lat: +points.lat, lng: +points.lng }}
					defaultZoom={15}
					distanceToMouse={distanceToMouse}
				>
					{points.title !== 'Current Location' && <MyMarker key={points.id} lat={points.lat} lng={points.lng} tooltip={points.title} />}
				</GoogleMapReact>
			</div>
		</div>
	);
};

export default MapPin;
